-- int_acs_2021_s2301
DROP TABLE IF EXISTS public.int_acs_2021_s2301 CASCADE;

CREATE TABLE public.int_acs_2021_s2301 AS
SELECT
    CASE WHEN NULLIF(BTRIM("year"), '') ~ '^-?\d+(\.\d+)?$' THEN BTRIM("year")::numeric ELSE NULL END::int AS year,
    tract_geoid,
    "geo_id",
    "name",
    "statefp",
    "countyfp",
    "tractce",
    "table_code",
    "table_family",
